// 주요 단어 하이라이트 처리 및 툴팁 추가 (다국어 지원)
const highlightKeywords = (text) => {
  if (!text) return '';
  
  // 현재 선택된 언어에 따른 사전 가져오기
  const currentDictionary = dictionaries[selectedLanguage] || {};
  
  // 중요 키워드 목록 (언어별로 다르게 정의할 수도 있음)
  const keywords = {
    english: ['describe', 'explain', 'reflect', 'compare', 'analyze'],
    japanese: ['説明する', '比較する', '分析する'],
    chinese: ['描述', '解释', '比较'],
    spanish: ['describir', 'explicar', 'comparar'],
    french: ['décrire', 'expliquer', 'comparer'],
    korean: ['설명하다', '비교하다', '분석하다'],
    german: ['beschreiben', 'erklären', 'vergleichen'],
    russian: ['описывать', 'объяснять', 'сравнивать'],
    arabic: ['وصف', 'شرح', 'مقارنة'],
    vietnamese: ['mô tả', 'giải thích', 'so sánh'],
    thai: ['อธิบาย', 'ชี้แจง', 'เปรียบเทียบ'],
    indonesian: ['menjelaskan', 'menerangkan', 'membandingkan']
  };
  
  // 현재 언어의 키워드
  const currentKeywords = keywords[selectedLanguage] || keywords.english;
  
  // 단어 단위로 분리하여 처리
  // 모든 언어 유형에 대응할 수 있도록 정규식 패턴 개선
  const words = text.split(/\b|(?=[\u3040-\u30ff\u3400-\u4dbf\u4e00-\u9fff\u0600-\u06FF\uAC00-\uD7A3])|(?<=[\u3040-\u30ff\u3400-\u4dbf\u4e00-\u9fff\u0600-\u06FF\uAC00-\uD7A3])/);
  
  const processedWords = words.map(word => {
    if (!word || word.trim() === '') return word;
    
    // 소문자로 변환하여 검사 (영어 및 로마자 기반 언어)
    const lowerWord = word.toLowerCase().trim();
    
    // 번역 가능한 단어인지 확인 (영어 및 로마자 기반 언어)
    if (lowerWord.length > 1) {
      // 단어 사전에서 번역 찾기
      const translation = currentDictionary[lowerWord] || "";
      
      // 키워드는 굵게 및 색상 적용 + 툴팁 추가
      if (currentKeywords.some(keyword => lowerWord.includes(keyword) || word.includes(keyword))) {
        return `<span class="highlight-keyword tooltip" data-translation="${translation}">${word}</span>`;
      } else if (word.length > 5) {
        // 긴 단어는 약간의 강조 + 툴팁 추가
        return `<span class="highlight-long tooltip" data-translation="${translation}">${word}</span>`;
      } else {
        // 일반 단어도 툴팁 추가
        return `<span class="tooltip" data-translation="${translation}">${word}</span>`;
      }
    }
    return word;
  });
  
  return processedWords.join('');
};

