// 선택된 언어 및 성별에 따라 적절한 음성 객체 반환
const getSelectedVoice = () => {
  // 로컬에서 사용 가능한 음성 확인
  const voices = availableVoices.length > 0 ? 
    availableVoices : 
    window.speechSynthesis.getVoices();
  
  let selectedVoice = null;
  const currentLang = languageData[selectedLanguage].code;
  
  // 선택된 언어와 성별에 맞는 음성 찾기
  if (voiceGender === 'female') {
    selectedVoice = voices.find(v => 
      v.lang.includes(currentLang) && 
      (v.name.includes('Female') || v.name.includes('female'))
    );
  } else {
    selectedVoice = voices.find(v => 
      v.lang.includes(currentLang) && 
      (v.name.includes('Male') || v.name.includes('male'))
    );
  }
  
  // 대체 옵션 - 해당 언어의 아무 음성
  if (!selectedVoice) {
    selectedVoice = voices.find(v => v.lang.includes(currentLang));
  }
  
  // 기본 음성으로 폴백
  return selectedVoice || voices[0];
};

// 개선된 질문 음성 출력 함수
const speakQuestionWithSelectedVoice = (text) => {
  // 기존 발화 중지
  if (window.speechSynthesis.speaking) {
    window.speechSynthesis.cancel();
  }
  
  // 음성 합성 객체 생성
  const utterance = new SpeechSynthesisUtterance(text);
  
  // 자연스러운 발화를 위한 설정
  utterance.rate = questionPlaybackRate;
  utterance.pitch = 1.0;
  utterance.volume = 1.0;
  
  // 선택된 음성 적용
  const voice = getSelectedVoice();
  if (voice) {
    utterance.voice = voice;
    console.log("Speaking with voice:", voice.name);
  }
  
  // 문장 단위로 나누어 더 자연스럽게 말하기
  // 범용 문장 분리 정규식 (대부분의 언어에 적용 가능)
  const sentences = text.match(/[^.!?。！？]+[.!?。！？]+/g) || [text];
  
  // 문장 사이에 약간의 간격을 두고 발화
  let delay = 0;
  sentences.forEach((sentence, index) => {
    setTimeout(() => {
      const sentenceUtterance = new SpeechSynthesisUtterance(sentence.trim());
      sentenceUtterance.rate = questionPlaybackRate;
      sentenceUtterance.pitch = 1.0;
      sentenceUtterance.volume = 1.0;
      if (voice) sentenceUtterance.voice = voice;
      
      window.speechSynthesis.speak(sentenceUtterance);
    }, delay);
    
    // 문장 길이에 비례해 다음 문장까지의 간격 계산
    delay += (sentence.length * 80 * (1/questionPlaybackRate));
  });
};

